function buildEvolution(dates,allDays){const counts={};dates.forEach(d=>{counts[d]=(counts[d]||0)+1;});let acc=0;return allDays.map(day=>{acc+=(counts[day]||0);return acc;});}
function buildMovEvolution(movArr){let acc=0;return ALL_DAYS_MAR.map((_,i)=>{acc+=(movArr[i]||0);return acc;});}

const Tip=({active,payload,label})=>{if(!active||!payload||!payload.length)return null;return(<div style={{background:C.dark,color:'#fff',padding:'10px 14px',borderRadius:6,fontSize:12,fontFamily:FONT,boxShadow:'0 8px 24px rgba(0,0,0,0.35)',border:'1px solid #333',minWidth:120}}><div style={{fontWeight:700,marginBottom:5,color:'#AAA',fontSize:10,textTransform:'uppercase'}}>{label}</div>{payload.map((p,i)=>(<div key={i} style={{display:'flex',gap:8,alignItems:'center',marginBottom:2}}><div style={{width:8,height:8,borderRadius:2,background:p.fill||p.color||C.orange,flexShrink:0}}/><span style={{color:'#CCC',fontSize:11}}>{p.name}:</span><strong style={{color:'white'}}>{typeof p.value==='number'?p.value.toLocaleString('pt-BR'):p.value}</strong></div>))}</div>);};
function Badge({label,color=C.orange,bg}){return(<span style={{fontSize:10,fontWeight:700,padding:'2px 7px',borderRadius:3,background:bg||color+'18',color,display:'inline-block',lineHeight:1.7,whiteSpace:'nowrap',fontFamily:FONT}}>{label}</span>);}
function KPICard({title,value,note,icon}){return(<div style={{background:C.white,borderRadius:8,padding:'16px 18px',border:`2px solid ${C.orange}`,boxShadow:C.shadow,flex:1,minWidth:0,fontFamily:FONT,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',textAlign:'center'}}><div style={{fontSize:10,color:C.gray,fontWeight:700,textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:6,display:'flex',alignItems:'center',justifyContent:'center',gap:5}}>{icon&&<span style={{fontSize:13}}>{icon}</span>}{title}</div><div style={{fontSize:28,fontWeight:800,color:C.orange,lineHeight:1.1}}>{typeof value==='number'?value.toLocaleString('pt-BR'):value}</div>{note&&<div style={{fontSize:11,color:C.gray,marginTop:4}}>{note}</div>}</div>);}
function Card({title,children,style:s={},action}){return(<div style={{background:C.white,borderRadius:8,padding:'14px 16px',boxShadow:C.shadow,overflow:'hidden',fontFamily:FONT,...s}}>{(title||action)&&(<div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:12,gap:8}}><div style={{display:'flex',alignItems:'center',gap:8,minWidth:0}}><div style={{width:3,height:16,background:C.orange,borderRadius:2,flexShrink:0}}/><span style={{fontSize:12,fontWeight:700,color:C.text,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{title}</span></div>{action&&<div style={{flexShrink:0}}>{action}</div>}</div>)}{children}</div>);}
function PBar({label,actual,meta,color=C.orange}){const p=meta>0?Math.min(actual/meta*100,100):0,over=actual>=meta;return(<div style={{marginBottom:10,fontFamily:FONT}}><div style={{display:'flex',justifyContent:'space-between',marginBottom:3}}><span style={{fontSize:11,fontWeight:600,color:C.text}}>{label}</span><span style={{fontSize:11,color:C.gray}}><strong style={{color:over?C.green:C.text}}>{actual}</strong>/{meta}{over&&<span style={{color:C.green,marginLeft:3,fontWeight:700}}>v</span>}</span></div><div style={{height:7,background:C.grayL,borderRadius:4,overflow:'hidden'}}><div style={{height:'100%',width:`${p}%`,background:over?C.green:color,borderRadius:4}}/></div></div>);}
function TblHead({cols}){return(<thead><tr style={{background:C.grayL,borderBottom:`1.5px solid ${C.border}`}}>{cols.map(h=>(<th key={h} style={{padding:'7px 10px',textAlign:'left',fontSize:9.5,fontWeight:700,color:C.gray,textTransform:'uppercase',whiteSpace:'nowrap',fontFamily:FONT}}>{h}</th>))}</tr></thead>);}
const tRow=i=>({borderBottom:`1px solid ${C.border}`,background:i%2===0?C.white:C.grayL});
function fmtDt(iso){if(!iso)return "—";const p=iso.split("-");return p[2]+"/"+p[1];}
function calcAging(ini,fim){if(!ini)return null;const f=fim?new Date(fim):new Date();return Math.floor((f-new Date(ini))/864e5);}

function ParceriasPage({dateIni,dateFim}){
  const[selParceiro,setSelParceiro]=useState('Todos');
  const[selStatus,setSelStatus]=useState('Todos');
  const parceiros=useMemo(()=>['Todos',...[...new Set(PARCERIAS_RAW.map(r=>r[P.PARCEIRO]))].sort()],[]);
  const FL=useMemo(()=>PARCERIAS_RAW.filter(r=>{
    if(selParceiro!=='Todos'&&r[P.PARCEIRO]!==selParceiro)return false;
    if(selStatus!=='Todos'&&r[P.STATUS]!==selStatus)return false;
    if(dateIni||dateFim){
      if(!r[P.DATA_IND])return false;
      const parts=r[P.DATA_IND].split('/');
      if(parts.length<3)return false;
      const iso=`${parts[2]}-${parts[1].padStart(2,'0')}-${parts[0].padStart(2,'0')}`;
      if(!inRange(iso,dateIni,dateFim))return false;
    }
    return true;
  }),[selParceiro,selStatus,dateIni,dateFim]);
  const perdidos=FL.filter(r=>r[P.STATUS]==='Perdida').length,ativos=FL.filter(r=>r[P.STATUS]==='Em Andamento').length,total=ativos,comReuniao=FL.filter(r=>r[P.STATUS]==='Em Andamento'&&r[P.REUNIAO]==='Sim').length;
  const totalAtivos=PARCERIAS_RAW.filter(r=>r[P.STATUS]==='Em Andamento').length;
  const totalPerdidos=PARCERIAS_RAW.filter(r=>r[P.STATUS]==='Perdida').length;
  const porParceiro=useMemo(()=>{const m={};PARCERIAS_RAW.forEach(r=>{const p=r[P.PARCEIRO];if(!m[p])m[p]={parceiro:p,total:0,ativos:0,perdidos:0,reunioes:0};m[p].total++;if(r[P.STATUS]==='Em Andamento')m[p].ativos++;if(r[P.STATUS]==='Perdida')m[p].perdidos++;if(r[P.REUNIAO]==='Sim')m[p].reunioes++;});return Object.values(m).sort((a,b)=>b.total-a.total);},[]);
  const porMes=useMemo(()=>{const m={};FL.forEach(r=>{if(!r[P.DATA_IND])return;const parts=r[P.DATA_IND].split('/');if(parts.length<3)return;if(parts[2]!=='2026')return;const key=`${parts[2]}-${parts[1].padStart(2,'0')}`;if(!m[key])m[key]={label:`${parts[1].padStart(2,'0')}/${parts[2].slice(2)}`,key,leads:0,reunioes:0};m[key].leads++;if(r[P.REUNIAO]==='Sim')m[key].reunioes++;});return Object.values(m).sort((a,b)=>a.key.localeCompare(b.key));},[FL]);
  const leadsPorMes2026=useMemo(()=>{const m={};PARCERIAS_RAW.forEach(r=>{if(!r[P.DATA_IND])return;const parts=r[P.DATA_IND].split('/');if(parts.length<3||parts[2]!=='2026')return;const key=`${parts[2]}-${parts[1].padStart(2,'0')}`;const label=`${parts[1].padStart(2,'0')}/${parts[2].slice(2)}`;if(!m[key])m[key]={label,key,leads:0};m[key].leads++;});return Object.values(m).sort((a,b)=>a.key.localeCompare(b.key));},[]);
  const totalLeads2026=leadsPorMes2026.reduce((a,b)=>a+b.leads,0);
  const porEtapa=useMemo(()=>{const m={};FL.forEach(r=>{if(r[P.ETAPA])m[r[P.ETAPA]]=(m[r[P.ETAPA]]||0)+1;});return ETAPA_ORDER.filter(e=>m[e]).map(e=>({etapa:e,count:m[e]}));},[FL]);
  const porResponsavel=useMemo(()=>{const m={};PARCERIAS_RAW.forEach(r=>{const resp=r[P.RESP]||'Nao informado';if(!m[resp])m[resp]={resp,total:0,ativos:0,perdidos:0,reunioes:0};m[resp].total++;if(r[P.STATUS]==='Em Andamento')m[resp].ativos++;if(r[P.STATUS]==='Perdida')m[resp].perdidos++;if(r[P.REUNIAO]==='Sim')m[resp].reunioes++;});return Object.values(m).sort((a,b)=>b.total-a.total);},[]);
  const slBtn=(active,color=C.orange)=>({padding:'4px 11px',borderRadius:20,border:`1.5px solid ${active?color:C.border}`,background:active?color:C.white,color:active?C.white:C.gray,fontSize:11,fontWeight:600,cursor:'pointer',flexShrink:0,fontFamily:FONT});
  return(<div style={{display:'flex',flexDirection:'column',gap:11}}>
    <div style={{background:C.white,borderRadius:8,padding:'12px 16px',boxShadow:C.shadow}}>
      <div style={{display:'flex',flexDirection:'column',gap:9}}>
        <div style={{display:'flex',alignItems:'center',gap:8,flexWrap:'wrap'}}><span style={{fontSize:10,fontWeight:700,color:C.gray,textTransform:'uppercase',letterSpacing:'0.07em',minWidth:72}}>Parceiro</span><div style={{display:'flex',gap:5,flexWrap:'wrap'}}>{parceiros.map(p=>(<button key={p} onClick={()=>setSelParceiro(p)} style={slBtn(selParceiro===p,PARTNER_COLORS[p]||C.orange)}>{p}</button>))}</div></div>
        <div style={{display:'flex',alignItems:'center',gap:8,flexWrap:'wrap'}}><span style={{fontSize:10,fontWeight:700,color:C.gray,textTransform:'uppercase',letterSpacing:'0.07em',minWidth:72}}>Status</span>{['Todos','Em Andamento','Perdida'].map(s=>(<button key={s} onClick={()=>setSelStatus(s)} style={slBtn(selStatus===s,s==='Perdida'?'#4A4B4D':C.orange)}>{s}</button>))}</div>
      </div>
    </div>
    <div style={{display:'flex',gap:9}}>
      <KPICard title="Leads Ativos" value={totalAtivos} icon="🤝" note={`${totalPerdidos} perdidos`}/>
      <KPICard title="Com Reuniao" value={comReuniao} icon="📅" note={`${pctN(comReuniao,totalAtivos).toFixed(0)}% dos ativos`}/>
      <KPICard title="Perdidos" value={totalPerdidos} icon="❌" note={`${Math.round(totalPerdidos/(totalAtivos+totalPerdidos)*100)}% do total`}/>
      <KPICard title="Leads Entrados em 2026" value={totalLeads2026} icon="📈" note={`${leadsPorMes2026.length} meses com indicacoes`}/>
    </div>
    <Card title="Leads Entrados por Mes — 2026">
      <ResponsiveContainer width="100%" height={200}>
        <ComposedChart data={leadsPorMes2026} margin={{top:20,right:20,left:0,bottom:0}}>
          <CartesianGrid strokeDasharray="3 3" stroke={C.grayL}/>
          <XAxis dataKey="label" tick={{fontSize:11,fill:C.gray,fontFamily:FONT}}/>
          <YAxis tick={{fontSize:11,fill:C.gray,fontFamily:FONT}} allowDecimals={false}/>
          <Tooltip content={<Tip/>}/>
          <Bar dataKey="leads" name="Leads Entrados" fill={C.orange} radius={[4,4,0,0]} barSize={42}>
            <LabelList dataKey="leads" position="top" style={{fontSize:11,fill:C.orange,fontWeight:800}} formatter={v=>v>0?v:''}/>
          </Bar>
          <Line dataKey="leads" name="Tendencia" stroke={"#8C5200"} strokeWidth={2} strokeDasharray="4 3" type="monotone" dot={{r:4,fill:"#8C5200",stroke:'#fff',strokeWidth:2}}/>
        </ComposedChart>
      </ResponsiveContainer>
    </Card>
    <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:11}}>
      <Card title="Ranking de Parceiros">
        <div style={{overflowX:'auto',borderRadius:6,border:`1px solid ${C.border}`}}>
          <table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}>
            <TblHead cols={['Parceiro','Total','Ativos','Perdidos','Reunioes','Tx. Perda']}/>
            <tbody>{porParceiro.map((r,i)=>{const txP=r.total>0?Math.round(r.perdidos/r.total*100):0;const color=PARTNER_COLORS[r.parceiro]||C.gray;return(<tr key={i} style={{...tRow(i),cursor:'pointer'}} onClick={()=>setSelParceiro(r.parceiro===selParceiro?'Todos':r.parceiro)}><td style={{padding:'7px 10px'}}><div style={{display:'flex',alignItems:'center',gap:7}}><div style={{width:10,height:10,borderRadius:3,background:color,flexShrink:0}}/><span style={{fontWeight:600}}>{r.parceiro}</span></div></td><td style={{padding:'7px 10px',fontWeight:800,fontSize:13,color}}>{r.total}</td><td style={{padding:'7px 10px',color:C.orange,fontWeight:700}}>{r.ativos}</td><td style={{padding:'7px 10px',color:r.perdidos>0?"#4A4B4D":C.gray,fontWeight:700}}>{r.perdidos||'—'}</td><td style={{padding:'7px 10px',color:"#8C5200",fontWeight:700}}>{r.reunioes||'—'}</td><td style={{padding:'7px 10px'}}><Badge label={`${txP}%`} color={txP>40?"#4A4B4D":txP>20?"#8C5200":C.orange} bg={txP>40?"#EBEBEB":txP>20?"#FFF0D6":C.oL}/></td></tr>);})}</tbody>
          </table>
        </div>
      </Card>
      <Card title="Volume por Parceiro — Ativos vs Perdidos">
        <ResponsiveContainer width="100%" height={260}>
          <BarChart data={porParceiro} layout="vertical">
            <CartesianGrid strokeDasharray="3 3" stroke={C.grayL} horizontal={false}/><XAxis type="number" tick={{fontSize:10,fill:C.gray,fontFamily:FONT}}/><YAxis dataKey="parceiro" type="category" tick={{fontSize:9,fill:C.gray,fontFamily:FONT}} width={115}/><Tooltip content={<Tip/>}/><Legend wrapperStyle={{fontSize:10,fontFamily:FONT}}/>
            <Bar dataKey="ativos" name="Ativos" stackId="a" fill={C.orange} radius={[0,0,0,0]}><LabelList dataKey="ativos" position="insideLeft" style={{fontSize:9,fill:'white',fontWeight:700}} formatter={v=>v>0?v:''}/></Bar>
            <Bar dataKey="perdidos" name="Perdidos" stackId="a" fill={"#4A4B4D"} radius={[0,4,4,0]}><LabelList dataKey="perdidos" position="right" style={{fontSize:9,fill:"#4A4B4D",fontWeight:700}} formatter={v=>v>0?v:''}/></Bar>
          </BarChart>
        </ResponsiveContainer>
      </Card>
    </div>
    <div style={{display:'grid',gridTemplateColumns:'1.2fr 1fr',gap:11}}>
      <Card title="Indicacoes por Mes — Leads e Reunioes">
        <ResponsiveContainer width="100%" height={200}>
          <ComposedChart data={porMes}><CartesianGrid strokeDasharray="3 3" stroke={C.grayL}/><XAxis dataKey="label" tick={{fontSize:10,fill:C.gray,fontFamily:FONT}}/><YAxis tick={{fontSize:10,fill:C.gray,fontFamily:FONT}}/><Tooltip content={<Tip/>}/>
            <Bar dataKey="leads" name="Leads" fill={C.orange} radius={[4,4,0,0]}><LabelList dataKey="leads" position="top" style={{fontSize:9.5,fill:C.orange,fontWeight:700}} formatter={v=>v>0?v:''}/></Bar>
            <Bar dataKey="reunioes" name="Reunioes" fill={"#8C5200"} radius={[4,4,0,0]}><LabelList dataKey="reunioes" position="top" style={{fontSize:9.5,fill:"#8C5200",fontWeight:700}} formatter={v=>v>0?v:''}/></Bar>
          </ComposedChart>
        </ResponsiveContainer>
      </Card>
      <Card title="Etapas do Funil — Parcerias">
        {porEtapa.map((e,i)=>{const bw=porEtapa[0]?.count>0?pctN(e.count,porEtapa[0].count):0;return(<div key={i} style={{display:'flex',alignItems:'center',gap:6,marginBottom:5}}><div style={{width:130,fontSize:10,color:C.text,textAlign:'right',flexShrink:0,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{e.etapa}</div><div style={{flex:1,height:14,background:C.grayL,borderRadius:3,overflow:'hidden'}}><div style={{height:'100%',width:`${bw}%`,background:i===0?C.orange:i<3?"#8C5200":"#4A4B4D",opacity:Math.max(0.35,1-i*0.06),borderRadius:3}}/></div><span style={{fontSize:10,fontWeight:700,color:C.text,width:28,textAlign:'right',flexShrink:0}}>{e.count}</span></div>);})}
      </Card>
    </div>
    <Card title="Ranking de Responsáveis">
      <div style={{overflowX:'auto',borderRadius:6,border:`1px solid ${C.border}`}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}>
          <TblHead cols={['Responsável','Total','Ativos','Perdidos','Com Reunião']}/>
          <tbody>{porResponsavel.map((r,i)=>{return(<tr key={i} style={tRow(i)}><td style={{padding:'7px 10px',fontWeight:700,color:C.text}}>{r.resp}</td><td style={{padding:'7px 10px',fontWeight:800,fontSize:13,color:C.orange}}>{r.total}</td><td style={{padding:'7px 10px',color:C.orange,fontWeight:700}}>{r.ativos}</td><td style={{padding:'7px 10px',color:r.perdidos>0?"#4A4B4D":C.gray,fontWeight:700}}>{r.perdidos||'—'}</td><td style={{padding:'7px 10px',color:"#8C5200",fontWeight:700}}>{r.reunioes||'—'}</td></tr>);})}</tbody>
        </table>
      </div>
    </Card>
    <Card title={`Leads via Parceiros — ${FL.length} registros`}>
      <div style={{overflowX:'auto',borderRadius:6,border:`1px solid ${C.border}`}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:11,tableLayout:'fixed'}}>
          <colgroup><col style={{width:'20%'}}/><col style={{width:'15%'}}/><col style={{width:'12%'}}/><col style={{width:'14%'}}/><col style={{width:'8%'}}/><col style={{width:'8%'}}/><col style={{width:'11%'}}/><col style={{width:'12%'}}/></colgroup>
          <TblHead cols={['Empresa','Parceiro','Status','Etapa','Reuniao','Decisor','Frota','Responsavel']}/>
          <tbody>{FL.map((r,i)=>{const color=PARTNER_COLORS[r[P.PARCEIRO]]||C.gray;return(<tr key={i} style={tRow(i)}><td style={{padding:'6px 8px',fontWeight:600,color:C.text,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{r[P.EMPRESA]}</td><td style={{padding:'6px 8px'}}><div style={{display:'flex',alignItems:'center',gap:5}}><div style={{width:8,height:8,borderRadius:2,background:color,flexShrink:0}}/><span style={{fontSize:10.5}}>{r[P.PARCEIRO]}</span></div></td><td style={{padding:'6px 8px'}}><Badge label={r[P.STATUS]} color={r[P.STATUS]==='Em Andamento'?C.orange:"#4A4B4D"} bg={r[P.STATUS]==='Em Andamento'?C.oL:"#EBEBEB"}/></td><td style={{padding:'6px 8px'}}><Badge label={r[P.ETAPA]} color={C.orange}/></td><td style={{padding:'6px 8px',textAlign:'center'}}>{r[P.REUNIAO]==='Sim'?<span style={{color:C.orange,fontWeight:700}}>✓</span>:<span style={{color:'#CCC'}}>—</span>}</td><td style={{padding:'6px 8px',textAlign:'center'}}>{r[P.DECISOR]==='Sim'?<span style={{color:C.orange,fontWeight:700,fontSize:10}}>Sim</span>:<span style={{color:'#CCC'}}>—</span>}</td><td style={{padding:'6px 8px',color:C.gray,fontSize:10,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{r[P.FROTA]||'—'}</td><td style={{padding:'6px 8px',color:C.gray,fontSize:10,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{(r[P.RESP]||'').split(' ')[0]||'—'}</td></tr>);})}</tbody>
        </table>
      </div>
    </Card>
  </div>);
}

function DiagPage({dateIni,dateFim}){
  const[showConc,setShowConc]=useState(false);
  const[showDesc,setShowDesc]=useState(false);
  const[showAlerta,setShowAlerta]=useState(true);
  const DATA=useMemo(()=>{
    if(!dateIni&&!dateFim)return DIAG_DATA;
    return DIAG_DATA.filter(d=>{
      const datas=[d.dataInicio,d.dataConclusao].filter(Boolean);
      if(!datas.length)return !dateIni&&!dateFim;
      return datas.some(dt=>inRange(dt,dateIni,dateFim));
    });
  },[dateIni,dateFim]);
  const total=DATA.length;
  const concluidos=DATA.filter(d=>d.status==="COMPLETE").sort((a,b)=>a.empresa.localeCompare(b.empresa,"pt-BR"));
  const descartadas=DATA.filter(d=>d.status==="DESCARTADA").sort((a,b)=>a.empresa.localeCompare(b.empresa,"pt-BR"));
  const emAndamento=DATA.filter(d=>d.status!=="COMPLETE"&&d.status!=="DESCARTADA").sort((a,b)=>a.empresa.localeCompare(b.empresa,"pt-BR"));
  const pendenteApres=DIAG_DATA.filter(d=>d.status==="APRESENTACAO");
  const concluidaSemApres=DIAG_DATA.filter(d=>d.status==="COMPLETE"&&d.apresentacao==="Nao");
  const nConc=concluidos.length,nAtivo=emAndamento.length,nDesc=descartadas.length;
  const diasArr=DATA.filter(d=>d.dias!=null).map(d=>d.dias);
  const diasM=diasArr.length>0?Math.round(diasArr.reduce((a,b)=>a+b,0)/diasArr.length):0;
  const nSim=DATA.filter(d=>d.reforma==="Sim").length,nNao=DATA.filter(d=>d.reforma==="Nao").length;
  const nSimConc=concluidos.filter(d=>d.reforma==="Sim").length,nSimAtivo=emAndamento.filter(d=>d.reforma==="Sim").length;
  const nEnt=DATA.filter(d=>d.tam==="Enterprise").length,nPME=DATA.filter(d=>d.tam==="PME").length;
  const pctConc=total>0?Math.round(nConc/total*100):0;
  const bs=`1px solid ${C.border}`;
  const TH={padding:'6px 10px',background:'#F5F5F3',fontSize:10,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:`1px solid ${C.border}`,whiteSpace:'nowrap',textAlign:'left'};
  const THC={...TH,textAlign:'center'};
  const calcAg=(ini,fim)=>{if(!ini)return null;const f=fim?new Date(fim):new Date();return Math.floor((f-new Date(ini))/864e5);};
  const AgBadge=({d})=>{if(d===null)return <span style={{color:'#CCC'}}>—</span>;const col=d<=15?C.green:d<=30?C.orange:"#B35B00";const bg=d<=15?C.gL:d<=30?C.oL:"#FFF3E0";return <span style={{fontSize:10,fontWeight:700,background:bg,color:col,padding:'2px 7px',borderRadius:10,whiteSpace:'nowrap'}}>{d}d</span>;};
  const StBadge=({status})=>{const s=DIAG_STATUS[status]||{dot:C.gray,color:C.gray,label:status};return(<span style={{fontSize:10.5,color:s.color,fontWeight:600,whiteSpace:'nowrap'}}>{s.label}</span>);};
  const RefBadge=({v})=>{if(!v||v==='—')return <span style={{color:'#CCC'}}>—</span>;return <span style={{fontSize:11,fontWeight:700,color:v==='Sim'?'#2D9E60':C.orange}}>{v}</span>;};
  const UFBadge=({v})=>v?<span style={{fontSize:11,fontWeight:700,color:C.orange}}>{v}</span>:<span style={{color:'#CCC'}}>—</span>;
  const SegBadge=({v})=><span style={{fontSize:10,fontWeight:700,color:v==='Enterprise'?C.orange:'#888',background:v==='Enterprise'?C.oL:'#F0F0F0',padding:'2px 6px',borderRadius:4}}>{v==='Enterprise'?'ETP':'PME'}</span>;
  return(
  <div style={{display:'flex',flexDirection:'column',gap:10,fontFamily:FONT}}>
    <div style={{background:C.white,borderRadius:8,padding:'14px 20px',border:bs,boxShadow:C.shadow}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',flexWrap:'wrap',gap:8}}>
        <div><div style={{fontSize:14,fontWeight:800,color:C.text,letterSpacing:'-0.01em'}}>REPORT DE DIAGNÓSTICO</div><div style={{fontSize:11,color:C.gray,marginTop:2}}>{new Date().toLocaleDateString('pt-BR',{weekday:'long',day:'2-digit',month:'long',year:'numeric'})}</div></div>
        <div style={{display:'flex',alignItems:'center',gap:8}}><span style={{fontSize:13,fontWeight:800,color:C.dark,letterSpacing:'-0.02em'}}>RumoBrasil</span><div style={{width:28,height:28,borderRadius:6,background:C.orange,display:'flex',alignItems:'center',justifyContent:'center'}}><span style={{fontSize:13,fontWeight:900,color:'#fff'}}>R</span></div></div>
      </div>
    </div>
    {(pendenteApres.length>0||concluidaSemApres.length>0)&&showAlerta&&(
      <div style={{borderRadius:8,border:`1.5px solid #E65100`,background:'#FFF8F0',boxShadow:'0 2px 12px rgba(230,81,0,0.12)',overflow:'hidden'}}>
        <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'10px 16px',borderBottom:'1px solid #FFD0A0',background:'#FFF0E0'}}>
          <div style={{display:'flex',alignItems:'center',gap:8}}>
            <span style={{fontSize:16}}>⚠️</span>
            <span style={{fontSize:12,fontWeight:800,color:'#E65100',textTransform:'uppercase',letterSpacing:'0.06em'}}>Pendências de Apresentação</span>
            <span style={{background:'#E65100',color:'#fff',borderRadius:20,padding:'1px 8px',fontSize:10,fontWeight:800}}>{pendenteApres.length+concluidaSemApres.length}</span>
          </div>
          <button onClick={()=>setShowAlerta(false)} style={{border:'none',background:'none',cursor:'pointer',fontSize:16,color:'#AAA',lineHeight:1,padding:'0 4px'}}>✕</button>
        </div>
        <div style={{padding:'12px 16px',display:'flex',flexDirection:'column',gap:10}}>
          {pendenteApres.length>0&&(
            <div>
              <div style={{fontSize:10,fontWeight:700,color:'#E65100',textTransform:'uppercase',letterSpacing:'0.07em',marginBottom:6}}>🕐 Aguardando Apresentação — Diagnóstico em andamento</div>
              <div style={{display:'flex',flexDirection:'column',gap:4}}>
                {pendenteApres.map(d=>(
                  <div key={d.id} style={{display:'flex',alignItems:'center',gap:8,background:'#fff',borderRadius:6,padding:'7px 12px',border:'1px solid #FFD0A0'}}>
                    <div style={{width:7,height:7,borderRadius:'50%',background:'#CC6C00',flexShrink:0}}/>
                    <span style={{fontSize:12,fontWeight:700,color:C.text,flex:1}}>{d.empresa}</span>
                    <span style={{fontSize:10,color:'#888'}}>Resp: {d.executivo||'—'}</span>
                    <span style={{fontSize:10,fontWeight:700,color:'#CC6C00',background:'#FFF0D6',padding:'2px 8px',borderRadius:4,whiteSpace:'nowrap'}}>Apresentação pendente</span>
                  </div>
                ))}
              </div>
            </div>
          )}
          {concluidaSemApres.length>0&&(
            <div>
              <div style={{fontSize:10,fontWeight:700,color:C.red,textTransform:'uppercase',letterSpacing:'0.07em',marginBottom:6}}>✅ Concluídas — Apresentação não realizada</div>
              <div style={{display:'flex',flexDirection:'column',gap:4}}>
                {concluidaSemApres.map(d=>(
                  <div key={d.id} style={{display:'flex',alignItems:'center',gap:8,background:'#fff',borderRadius:6,padding:'7px 12px',border:'1px solid #FFCDD2'}}>
                    <div style={{width:7,height:7,borderRadius:'50%',background:C.red,flexShrink:0}}/>
                    <span style={{fontSize:12,fontWeight:700,color:C.text,flex:1}}>{d.empresa}</span>
                    <span style={{fontSize:10,color:'#888'}}>Resp: {d.executivo||'—'}</span>
                    <span style={{fontSize:10,fontWeight:700,color:C.red,background:C.rL,padding:'2px 8px',borderRadius:4,whiteSpace:'nowrap'}}>Não apresentado</span>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    )}
    {(pendenteApres.length>0||concluidaSemApres.length>0)&&!showAlerta&&(
      <button onClick={()=>setShowAlerta(true)} style={{display:'flex',alignItems:'center',gap:6,padding:'7px 14px',borderRadius:8,border:`1.5px solid #E65100`,background:'#FFF0E0',color:'#E65100',fontSize:11,fontWeight:700,cursor:'pointer',alignSelf:'flex-start',fontFamily:FONT}}>
        <span>⚠️</span> {pendenteApres.length+concluidaSemApres.length} pendência{pendenteApres.length+concluidaSemApres.length>1?'s':''} de apresentação
      </button>
    )}
    <div style={{display:'grid',gridTemplateColumns:'1.4fr 1fr 1fr 1fr 1.6fr',gap:10}}>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',textAlign:'center'}}>
        <div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:6}}>Pipeline Total</div>
        <div style={{display:'flex',alignItems:'center',gap:10,justifyContent:'center'}}>
          <span style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{total}</span>
          <div style={{display:'flex',gap:6}}>
            <div style={{background:C.oL,borderRadius:5,padding:'4px 10px',textAlign:'center'}}><div style={{fontSize:14,fontWeight:800,color:C.orange}}>{nEnt}</div><div style={{fontSize:8,color:C.orange,fontWeight:700,textTransform:'uppercase'}}>ETP</div></div>
            <div style={{background:'#F2F2F0',borderRadius:5,padding:'4px 10px',textAlign:'center'}}><div style={{fontSize:14,fontWeight:800,color:'#666'}}>{nPME}</div><div style={{fontSize:8,color:'#666',fontWeight:700,textTransform:'uppercase'}}>PME</div></div>
          </div>
        </div>
        <div style={{fontSize:10,color:'#AAA',marginTop:5}}>{pctConc}% concluído</div>
      </div>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,textAlign:'center',display:'flex',flexDirection:'column',alignItems:'center'}}><div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:4}}>Concluídos</div><div style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{nConc}</div><div style={{fontSize:10,color:'#AAA',marginTop:4}}>{pctConc}% de conclusão</div></div>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,textAlign:'center',display:'flex',flexDirection:'column',alignItems:'center'}}><div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:4}}>Em Andamento</div><div style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{nAtivo}</div><div style={{fontSize:10,color:'#AAA',marginTop:4}}>{nAtivo} empresas ativas</div></div>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,textAlign:'center',display:'flex',flexDirection:'column',alignItems:'center'}}><div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:4}}>Prazo Médio</div><div style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{diasM}d</div><div style={{fontSize:10,color:'#AAA',marginTop:4}}>média para concluir</div></div>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',textAlign:'center'}}>
        <div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:6}}>Reforma Tributária</div>
        <div style={{display:'flex',alignItems:'center',gap:10,justifyContent:'center'}}>
          <span style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{nSim}</span>
          <div style={{display:'flex',gap:6}}>
            <div style={{background:C.gL,borderRadius:5,padding:'4px 10px',textAlign:'center'}}><div style={{fontSize:12,fontWeight:800,color:'#2D9E60'}}>{nSimConc}</div><div style={{fontSize:8,color:'#2D9E60',fontWeight:700,textTransform:'uppercase'}}>Conc.</div></div>
            <div style={{background:C.oL,borderRadius:5,padding:'4px 10px',textAlign:'center'}}><div style={{fontSize:12,fontWeight:800,color:C.orange}}>{nSimAtivo}</div><div style={{fontSize:8,color:C.orange,fontWeight:700,textTransform:'uppercase'}}>Ativos</div></div>
            <div style={{background:'#F2F2F0',borderRadius:5,padding:'4px 10px',textAlign:'center'}}><div style={{fontSize:12,fontWeight:800,color:'#888'}}>{nNao}</div><div style={{fontSize:8,color:'#888',fontWeight:700,textTransform:'uppercase'}}>Não optam</div></div>
          </div>
        </div>
        <div style={{fontSize:10,color:'#AAA',marginTop:5}}>{Math.round(nSim/total*100)}% optam</div>
      </div>
    </div>
    <div style={{display:'grid',gridTemplateColumns:'260px 1fr',gap:10,alignItems:'stretch'}}>
      <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden',display:'flex',flexDirection:'column'}}>
        <div style={{padding:'7px 12px',borderBottom:bs,background:'#F5F5F3',flexShrink:0}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Pipeline por Fase</span></div>
        <div style={{flex:1,padding:'12px',display:'flex',flexDirection:'column',justifyContent:'space-evenly',gap:4}}>
          {(()=>{const WIDTHS=[100,86,72,60,46,30];return FUNNEL_PHASES.map((f,i)=>{const cnt=DIAG_DATA.filter(d=>d.status===f.key).length;const col=cnt>0?f.bg:'#E8E8E8';const labelCol=cnt>0?f.bg:'#BBBBBB';const w=WIDTHS[i];return(<div key={f.key} style={{display:'flex',flexDirection:'column',alignItems:'center',gap:2}}><span style={{fontSize:11,fontWeight:600,color:labelCol,whiteSpace:'nowrap',lineHeight:1.2,textAlign:'center'}}>{f.label}</span><div style={{width:`${w}%`,height:26,background:col,borderRadius:4,display:'flex',alignItems:'center',justifyContent:'center'}}><span style={{fontSize:12,fontWeight:800,color:'#fff'}}>{cnt}</span></div></div>);});})()}
        </div>
      </div>
      <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden',display:'flex',flexDirection:'column'}}>
        <div style={{padding:'7px 14px',borderBottom:bs,background:'#F5F5F3',display:'flex',alignItems:'center',gap:8,flexShrink:0}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Em Andamento</span><span style={{background:C.oL,color:C.orange,borderRadius:20,padding:'1px 8px',fontSize:9,fontWeight:800}}>{nAtivo}</span></div>
        <div style={{overflowX:'auto',flex:1}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}><thead><tr><th style={{...TH,width:'17%'}}>Empresa</th><th style={{...THC,width:'11%'}}>Status</th><th style={{...THC,width:'12%'}}>Account Executive</th><th style={{...THC,width:'13%'}}>Responsável</th><th style={{...THC,width:'5%'}}>UF</th><th style={{...THC,width:'5%'}}>Seg.</th><th style={{...THC,width:'9%'}}>Dt. Entrada</th><th style={{...THC,width:'9%'}}>Dt. Conclusão</th><th style={{...THC,width:'7%'}}>Aging</th><th style={{...THC,width:'7%'}}>Reforma</th></tr></thead><tbody>{emAndamento.map((d,i)=>{const ag=calcAg(d.dataInicio,d.dataConclusao);return(<tr key={d.id} style={{borderBottom:`1px solid #F2F2F0`,background:i%2===0?C.white:'#FAFAF8'}}><td style={{padding:'7px 10px',fontWeight:700,fontSize:11,color:C.text,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',maxWidth:160}}>{d.empresa}</td><td style={{padding:'7px 10px',textAlign:'center'}}><StBadge status={d.status}/></td><td style={{padding:'7px 10px',textAlign:'center',fontSize:10.5,color:'#666'}}>{d.accountExecutive||'—'}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:10.5,color:'#666'}}>{d.executivo||'—'}</td><td style={{padding:'7px 10px',textAlign:'center'}}><UFBadge v={d.estado}/></td><td style={{padding:'7px 10px',textAlign:'center'}}><SegBadge v={d.tam}/></td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataInicio)}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataConclusao)}</td><td style={{padding:'7px 10px',textAlign:'center'}}><AgBadge d={ag}/></td><td style={{padding:'7px 10px',textAlign:'center'}}><RefBadge v={d.reforma}/></td></tr>);})}</tbody></table></div>
        <div style={{padding:'7px 14px',borderTop:bs,background:'#F5F5F3',display:'flex',alignItems:'center',gap:12,flexWrap:'wrap',flexShrink:0,marginTop:'auto'}}>
          <span style={{fontSize:8.5,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.06em'}}>Status:</span>
          {FUNNEL_PHASES.filter(f=>f.key!=='NAO INICIADA').map(f=>(<div key={f.key} style={{display:'flex',alignItems:'center',gap:3}}><div style={{width:7,height:7,borderRadius:'50%',background:f.bg}}/><span style={{fontSize:9,color:'#555'}}>{f.label}</span></div>))}
          <span style={{fontSize:8.5,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.06em',marginLeft:10}}>Aging:</span>
          {[['≤15d',C.green,C.gL,'Recente'],['16–30d',C.orange,C.oL,'Atenção'],['> 30d','#B35B00','#FFF3E0','Crítico']].map(([v,c,bg,l])=>(<div key={v} style={{display:'flex',alignItems:'center',gap:4}}><span style={{fontSize:9,background:bg,color:c,padding:'1px 6px',borderRadius:8,fontWeight:700}}>{v}</span><span style={{fontSize:9,color:'#555'}}>{l}</span></div>))}
        </div>
      </div>
    </div>
    <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden'}}>
      <div onClick={()=>setShowConc(v=>!v)} style={{padding:'7px 14px',background:'#F5F5F3',display:'flex',alignItems:'center',gap:8,cursor:'pointer',userSelect:'none'}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Concluídas</span><span style={{background:C.oL,color:C.orange,borderRadius:20,padding:'1px 8px',fontSize:9,fontWeight:800}}>{nConc}</span><span style={{marginLeft:'auto',fontSize:13,color:'#999',fontWeight:700}}>{showConc?'▲':'▼'}</span></div>
      {showConc&&<div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}><thead><tr><th style={{...TH,width:'22%'}}>Empresa</th><th style={{...THC,width:'13%'}}>Account Executive</th><th style={{...THC,width:'13%'}}>Responsável</th><th style={{...THC,width:'5%'}}>UF</th><th style={{...THC,width:'6%'}}>Seg.</th><th style={{...THC,width:'10%'}}>Dt. Entrada</th><th style={{...THC,width:'10%'}}>Dt. Conclusão</th><th style={{...THC,width:'8%'}}>Reforma</th><th style={{...THC,width:'9%'}}>Apresentação</th></tr></thead><tbody>{concluidos.map((d,i)=>(<tr key={d.id} style={{borderBottom:`1px solid #F2F2F0`,background:i%2===0?C.white:'#FAFAF8'}}><td style={{padding:'7px 10px',fontWeight:700,fontSize:11,color:C.text,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',maxWidth:200}}>{d.empresa}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.accountExecutive||'—'}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.executivo||'—'}</td><td style={{padding:'7px 10px',textAlign:'center'}}><UFBadge v={d.estado}/></td><td style={{padding:'7px 10px',textAlign:'center'}}><SegBadge v={d.tam}/></td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataInicio)}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataConclusao)}</td><td style={{padding:'7px 10px',textAlign:'center'}}><RefBadge v={d.reforma}/></td><td style={{padding:'7px 10px',textAlign:'center'}}><span style={{fontSize:11,fontWeight:700,color:d.apresentacao==='Sim'?'#2D9E60':C.red,background:d.apresentacao==='Sim'?C.gL:C.rL,padding:'2px 8px',borderRadius:4}}>{d.apresentacao||'—'}</span></td></tr>))}</tbody></table></div>}
    </div>
    <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden'}}>
      <div onClick={()=>setShowDesc(v=>!v)} style={{padding:'7px 14px',background:'#F5F5F3',display:'flex',alignItems:'center',gap:8,cursor:'pointer',userSelect:'none'}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Descartadas</span><span style={{background:C.rL,color:C.red,borderRadius:20,padding:'1px 8px',fontSize:9,fontWeight:800}}>{nDesc}</span><span style={{marginLeft:'auto',fontSize:13,color:'#999',fontWeight:700}}>{showDesc?'▲':'▼'}</span></div>
      {showDesc&&<div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}><thead><tr><th style={{...TH,width:'24%'}}>Empresa</th><th style={{...THC,width:'14%'}}>Account Executive</th><th style={{...THC,width:'14%'}}>Responsável</th><th style={{...THC,width:'6%'}}>UF</th><th style={{...THC,width:'7%'}}>Seg.</th><th style={{...THC,width:'11%'}}>Dt. Entrada</th><th style={{...THC,width:'11%'}}>Dt. Conclusão</th><th style={{...THC,width:'9%'}}>Reforma</th></tr></thead><tbody>{descartadas.map((d,i)=>(<tr key={d.id} style={{borderBottom:`1px solid #F2F2F0`,background:i%2===0?C.white:'#FAFAF8'}}><td style={{padding:'7px 10px',fontWeight:700,fontSize:11,color:'#888',whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',maxWidth:200}}>{d.empresa}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.accountExecutive||'—'}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.executivo||'—'}</td><td style={{padding:'7px 10px',textAlign:'center'}}><UFBadge v={d.estado}/></td><td style={{padding:'7px 10px',textAlign:'center'}}><SegBadge v={d.tam}/></td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataInicio)}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataConclusao)}</td><td style={{padding:'7px 10px',textAlign:'center'}}><RefBadge v={d.reforma}/></td></tr>))}</tbody></table></div>}
    </div>
    <DiagRTCPage/>
  </div>);
}

function DiagRTCPage(){
  const[showEnc,setShowEnc]=useState(false);
  const[showNaoIni,setShowNaoIni]=useState(true);
  const total=DIAG_RTC_DATA.filter(d=>d.empresa!=="CLIENTE X").length;
  const encerrados=DIAG_RTC_DATA.filter(d=>d.status==="ENCERRADO").sort((a,b)=>a.empresa.localeCompare(b.empresa,"pt-BR"));
  const naoIniciadas=DIAG_RTC_DATA.filter(d=>d.status==="NAO INICIADO"&&d.empresa!=="CLIENTE X").sort((a,b)=>a.empresa.localeCompare(b.empresa,"pt-BR"));
  const emAndamento=DIAG_RTC_DATA.filter(d=>d.status!=="ENCERRADO"&&d.status!=="NAO INICIADO"&&d.empresa!=="CLIENTE X").sort((a,b)=>a.empresa.localeCompare(b.empresa,"pt-BR"));
  const nEnc=encerrados.length,nAtivo=emAndamento.length,nNaoIni=naoIniciadas.length;
  const pctEnc=Math.round(nEnc/total*100);
  const bs=`1px solid ${C.border}`;
  const TH={padding:'6px 10px',background:'#F5F5F3',fontSize:10,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.05em',borderBottom:`1px solid ${C.border}`,whiteSpace:'nowrap',textAlign:'left'};
  const THC={...TH,textAlign:'center'};
  const StBadge=({status})=>{const s=RTC_STATUS[status]||{color:C.gray,label:status};return(<span style={{fontSize:10.5,color:s.color,fontWeight:600,whiteSpace:'nowrap'}}>{s.label}</span>);};
  const AgBadge=({d})=>{if(d===null)return <span style={{color:'#CCC'}}>—</span>;const col=d<=15?C.green:d<=30?C.orange:"#B35B00";const bg=d<=15?C.gL:d<=30?C.oL:"#FFF3E0";return <span style={{fontSize:10,fontWeight:700,background:bg,color:col,padding:'2px 7px',borderRadius:10,whiteSpace:'nowrap'}}>{d}d</span>;};
  return(
  <div style={{display:'flex',flexDirection:'column',gap:10,fontFamily:FONT,marginTop:20}}>
    <div style={{background:C.white,borderRadius:8,padding:'14px 20px',border:bs,boxShadow:C.shadow}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',flexWrap:'wrap',gap:8}}>
        <div><div style={{fontSize:14,fontWeight:800,color:C.text,letterSpacing:'-0.01em'}}>REPORT DIAGNÓSTICO REFORMA</div><div style={{fontSize:11,color:C.gray,marginTop:2}}>{new Date().toLocaleDateString('pt-BR',{weekday:'long',day:'2-digit',month:'long',year:'numeric'})}</div></div>
        <div style={{display:'flex',alignItems:'center',gap:8}}><span style={{fontSize:13,fontWeight:800,color:C.dark,letterSpacing:'-0.02em'}}>RumoBrasil</span><div style={{width:28,height:28,borderRadius:6,background:C.orange,display:'flex',alignItems:'center',justifyContent:'center'}}><span style={{fontSize:13,fontWeight:900,color:'#fff'}}>R</span></div></div>
      </div>
    </div>
    <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:10}}>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',textAlign:'center'}}>
        <div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:6}}>Pipeline Total</div>
        <div style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{total}</div>
        <div style={{fontSize:10,color:'#AAA',marginTop:5}}>{pctEnc}% concluído</div>
      </div>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,textAlign:'center',display:'flex',flexDirection:'column',alignItems:'center'}}><div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:4}}>Concluídos</div><div style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{nEnc}</div><div style={{fontSize:10,color:'#AAA',marginTop:4}}>{pctEnc}% de conclusão</div></div>
      <div style={{background:C.white,borderRadius:8,padding:'12px 16px',border:bs,boxShadow:C.shadow,textAlign:'center',display:'flex',flexDirection:'column',alignItems:'center'}}><div style={{fontSize:9,fontWeight:700,color:'#AAA',textTransform:'uppercase',letterSpacing:'0.08em',marginBottom:4}}>Em Andamento</div><div style={{fontSize:32,fontWeight:800,color:C.text,lineHeight:1}}>{nAtivo}</div><div style={{fontSize:10,color:'#AAA',marginTop:4}}>{nAtivo} empresas ativas</div></div>
    </div>
    <div style={{display:'grid',gridTemplateColumns:'260px 1fr',gap:10,alignItems:'stretch'}}>
      <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden',display:'flex',flexDirection:'column'}}>
        <div style={{padding:'7px 12px',borderBottom:bs,background:'#F5F5F3',flexShrink:0}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Pipeline por Fase</span></div>
        <div style={{flex:1,padding:'12px',display:'flex',flexDirection:'column',justifyContent:'space-evenly',gap:6}}>
          {(()=>{const WIDTHS=[100,72,40];return RTC_FUNNEL_PHASES.map((f,i)=>{const cnt=DIAG_RTC_DATA.filter(d=>d.status===f.key&&d.empresa!=="CLIENTE X").length;const col=cnt>0?f.bg:'#E8E8E8';const labelCol=cnt>0?f.bg:'#BBBBBB';const w=WIDTHS[i];return(<div key={f.key} style={{display:'flex',flexDirection:'column',alignItems:'center',gap:2}}><span style={{fontSize:11,fontWeight:600,color:labelCol,whiteSpace:'nowrap',lineHeight:1.2,textAlign:'center'}}>{f.label}</span><div style={{width:`${w}%`,height:26,background:col,borderRadius:4,display:'flex',alignItems:'center',justifyContent:'center'}}><span style={{fontSize:12,fontWeight:800,color:'#fff'}}>{cnt}</span></div></div>);});})()}
        </div>
      </div>
      <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden'}}>
        <div style={{padding:'7px 14px',borderBottom:bs,background:'#F5F5F3',display:'flex',alignItems:'center',gap:8}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Em Andamento / Programação</span><span style={{background:C.oL,color:C.orange,borderRadius:20,padding:'1px 8px',fontSize:9,fontWeight:800}}>{nAtivo}</span></div>
        <div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}><thead><tr><th style={{...TH,width:'30%'}}>Empresa</th><th style={{...THC,width:'15%'}}>Status</th><th style={{...THC,width:'20%'}}>Responsável</th><th style={{...THC,width:'15%'}}>Dt. Início</th><th style={{...THC,width:'15%'}}>Dt. Conclusão</th><th style={{...THC,width:'10%'}}>Aging</th></tr></thead><tbody>{emAndamento.map((d,i)=>{const ag=calcAging(d.dataInicio,d.dataConclusao);return(<tr key={d.id} style={{borderBottom:`1px solid #F2F2F0`,background:i%2===0?C.white:'#FAFAF8'}}><td style={{padding:'7px 10px',fontWeight:700,fontSize:11,color:C.text,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',maxWidth:200}}>{d.empresa}</td><td style={{padding:'7px 10px',textAlign:'center'}}><StBadge status={d.status}/></td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.responsavel||'—'}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataInicio)}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataConclusao)}</td><td style={{padding:'7px 10px',textAlign:'center'}}><AgBadge d={ag}/></td></tr>);})}</tbody></table></div>
        <div style={{padding:'7px 14px',borderTop:bs,background:'#F5F5F3',display:'flex',alignItems:'center',gap:12,flexWrap:'wrap'}}>
          {RTC_FUNNEL_PHASES.filter(f=>f.key!=='ENCERRADO'&&f.key!=='NAO INICIADO').map(f=>(<div key={f.key} style={{display:'flex',alignItems:'center',gap:3}}><div style={{width:7,height:7,borderRadius:'50%',background:f.bg}}/><span style={{fontSize:9,color:'#555'}}>{f.label}</span></div>))}
        </div>
      </div>
    </div>
    <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden'}}>
      <div onClick={()=>setShowNaoIni(v=>!v)} style={{padding:'7px 14px',background:'#F5F5F3',display:'flex',alignItems:'center',gap:8,cursor:'pointer',userSelect:'none'}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Não Iniciadas</span><span style={{background:'#EBEBEB',color:'#4A4B4D',borderRadius:20,padding:'1px 8px',fontSize:9,fontWeight:800}}>{nNaoIni}</span><span style={{marginLeft:'auto',fontSize:13,color:'#999',fontWeight:700}}>{showNaoIni?'▲':'▼'}</span></div>
      {showNaoIni&&<div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}><thead><tr><th style={{...TH,width:'40%'}}>Empresa</th><th style={{...THC,width:'30%'}}>Responsável</th><th style={{...THC,width:'15%'}}>Dt. Início</th><th style={{...THC,width:'15%'}}>Dt. Conclusão</th></tr></thead><tbody>{nNaoIni===0?(<tr><td colSpan={4} style={{padding:'18px',textAlign:'center',color:'#AAA',fontSize:11,fontStyle:'italic'}}>Nenhuma empresa aguardando início no momento.</td></tr>):naoIniciadas.map((d,i)=>(<tr key={d.id} style={{borderBottom:`1px solid #F2F2F0`,background:i%2===0?C.white:'#FAFAF8'}}><td style={{padding:'7px 10px',fontWeight:700,fontSize:11,color:'#4A4B4D'}}>{d.empresa}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.responsavel||'—'}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataInicio)}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataConclusao)}</td></tr>))}</tbody></table></div>}
    </div>
    <div style={{background:C.white,borderRadius:8,border:bs,boxShadow:C.shadow,overflow:'hidden'}}>
      <div onClick={()=>setShowEnc(v=>!v)} style={{padding:'7px 14px',background:'#F5F5F3',display:'flex',alignItems:'center',gap:8,cursor:'pointer',userSelect:'none'}}><span style={{fontSize:9,fontWeight:700,color:'#999',textTransform:'uppercase',letterSpacing:'0.07em'}}>Concluídos</span><span style={{background:C.oL,color:C.orange,borderRadius:20,padding:'1px 8px',fontSize:9,fontWeight:800}}>{nEnc}</span><span style={{marginLeft:'auto',fontSize:13,color:'#999',fontWeight:700}}>{showEnc?'▲':'▼'}</span></div>
      {showEnc&&<div style={{overflowX:'auto'}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:11}}><thead><tr><th style={{...TH,width:'30%'}}>Empresa</th><th style={{...THC,width:'20%'}}>Responsável</th><th style={{...THC,width:'15%'}}>Dt. Início</th><th style={{...THC,width:'15%'}}>Dt. Conclusão</th><th style={{...THC,width:'10%'}}>Prazo</th></tr></thead><tbody>{encerrados.map((d,i)=>(<tr key={d.id} style={{borderBottom:`1px solid #F2F2F0`,background:i%2===0?C.white:'#FAFAF8'}}><td style={{padding:'7px 10px',fontWeight:700,fontSize:11,color:C.text,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',maxWidth:200}}>{d.empresa}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#666'}}>{d.responsavel||'—'}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataInicio)}</td><td style={{padding:'7px 10px',textAlign:'center',fontSize:11,color:'#888'}}>{fmtDt(d.dataConclusao)}</td><td style={{padding:'7px 10px',textAlign:'center'}}>{d.dias!=null?<span style={{fontSize:10,fontWeight:700,background:C.gL,color:C.green,padding:'2px 7px',borderRadius:10}}>{d.dias}d</span>:<span style={{color:'#CCC'}}>—</span>}</td></tr>))}</tbody></table></div>}
    </div>
  </div>);
}

